const metricas = $('Postgres: Metricas de la Semana').first().json;
const respuestasBajas = $('Postgres: Respuestas con Score Bajo').all().map(i => i.json);
const slaHITL = $('Postgres: Cumplimiento SLA HITL').all().map(i => i.json);

// Calcular costo estimado OpenAI (aprox)
const costoEstimado = (metricas.total_tokens || 0) * 0.000005; // ~$5/1M tokens gpt-4o input

// Score compuesto de salud del sistema
const scoreHealth = (
  (metricas.avg_eval_score / 10) * 40 +
  (metricas.avg_rag_score || 0.8) * 30 +
  (metricas.p95_latencia < 8000 ? 1 : 0.5) * 20 +
  (metricas.total_errores / Math.max(metricas.total_consultas, 1) < 0.05 ? 1 : 0.5) * 10
);

// Identificar patrones de fallo
const patronesFallo = [];
if (metricas.avg_eval_score < 7) patronesFallo.push('eval_score_bajo: promedio ' + Math.round(metricas.avg_eval_score * 100) / 100);
if (metricas.avg_rag_score < 0.75) patronesFallo.push('rag_score_bajo: promedio ' + Math.round((metricas.avg_rag_score || 0) * 100) / 100);
if (metricas.p95_latencia > 8000) patronesFallo.push('latencia_alta: P95=' + metricas.p95_latencia + 'ms');
if (metricas.total_errores > 0) patronesFallo.push('errores_workflow: ' + metricas.total_errores + ' esta semana');

const slaEmergencia = slaHITL.find(s => s.urgencia_tipo === 'emergencia');
if (slaEmergencia && slaEmergencia.sla_pct < 95) {
  patronesFallo.push('SLA_BREACH_EMERGENCIA: ' + slaEmergencia.sla_pct + '% (objetivo 95%)');
}

return [{
  json: {
    semana_inicio: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    semana_fin: new Date().toISOString().split('T')[0],
    metricas: {
      ...metricas,
      costo_estimado_usd: Math.round(costoEstimado * 100) / 100,
      score_health_sistema: Math.round(scoreHealth * 10) / 10
    },
    respuestas_bajas_muestra: respuestasBajas.slice(0, 5),
    sla_hitl: slaHITL,
    patrones_fallo: patronesFallo,
    requiere_mejora_prompt: metricas.avg_eval_score < 7.0,
    requiere_reingestion_rag: (metricas.avg_rag_score || 0) < 0.75,
    tiene_sla_breach_emergencia: slaEmergencia ? slaEmergencia.sla_pct < 95 : false
  }
}];

