parameters.jsCode:
const rawResponse = $('HTTP: GPT-4o Analiza Fallos y Sugiere Mejoras').first().json;
const content = rawResponse.choices?.[0]?.message?.content || '{}';

let sugerencias;
try {
  sugerencias = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) {
  sugerencias = { analisis: content, mejoras_prompt: [], requiere_aprobacion_humana: true };
}

const metricas = $('Code: Consolidar Metricas Semanales').first().json;

// REGLA DE SEGURIDAD: si hay SLA breach de emergencias, siempre requiere aprobacion humana
if (metricas.tiene_sla_breach_emergencia) {
  sugerencias.requiere_aprobacion_humana = true;
  sugerencias.alerta_sla = 'SLA de emergencias no cumplido - requiere revision urgente del protocolo HITL';
}

return [{
  json: {
    ...metricas,
    sugerencias_ia: sugerencias,
    auto_aplicar: !sugerencias.requiere_aprobacion_humana && sugerencias.mejoras_prompt?.length > 0
  }
}];

